calculateMeanVariance:
(function (values) {
  var sum = values.reduce(function (acc, val) {
    return acc + val;
  }, 0);
  var mean = sum / values.length;
  var squaredDiffSum = values.reduce(function (acc, val) {
    var diff = val - mean;
    return acc + diff * diff;
  }, 0);
  var variance = squaredDiffSum / values.length;
  return { mean: mean, variance: variance };
})
